import java.util.*;

public class RbacEngine {

    private final Map<String, Set<String>> userRoles = new HashMap<>();
    private final Map<String, Set<String>> rolePermissions = new HashMap<>();

    public void assignRole(String username, String role) {
        userRoles.computeIfAbsent(username, k -> new HashSet<>()).add(role);
    }

    public void grantPermission(String role, String permission) {
        rolePermissions.computeIfAbsent(role, k -> new HashSet<>()).add(permission);
    }

    public boolean hasPermission(String username, String permission) {
        // Return true if any of the user's roles has the permission
        return false;
    }

    public Set<String> allPermissions(String username) {
        // Return union of all permissions across all user's roles
        return new HashSet<>();
    }

    public static void main(String[] args) {
        RbacEngine rbac = new RbacEngine();

        rbac.grantPermission("USER", "READ");
        rbac.grantPermission("USER", "WRITE");
        rbac.grantPermission("ADMIN", "READ");
        rbac.grantPermission("ADMIN", "WRITE");
        rbac.grantPermission("ADMIN", "DELETE");

        rbac.assignRole("alice", "USER");
        rbac.assignRole("bob", "ADMIN");

        System.out.println("Alice DELETE: " + rbac.hasPermission("alice", "DELETE"));
        System.out.println("Bob DELETE: " + rbac.hasPermission("bob", "DELETE"));
        System.out.println("Alice perms: " + rbac.allPermissions("alice").size());
        System.out.println("Bob perms: " + rbac.allPermissions("bob").size());
    }
}

import java.util.*;
import java.util.function.Supplier;

public class MethodSecurityInterceptor {

    private final Map<String, Set<String>> methodRoles = new HashMap<>();
    private final Map<String, Set<String>> userRoles = new HashMap<>();

    public void secureMethod(String methodName, String... requiredRoles) {
        methodRoles.put(methodName, new HashSet<>(List.of(requiredRoles)));
    }

    public void setUserRoles(String username, String... roles) {
        userRoles.put(username, new HashSet<>(List.of(roles)));
    }

    public <T> T invoke(String username, String methodName, Supplier<T> method) {
        // Check if user has at least one required role for the method
        // Throw SecurityException if access denied
        // Execute and return method result if access granted
        return null;
    }

    public static void main(String[] args) {
        MethodSecurityInterceptor interceptor = new MethodSecurityInterceptor();

        interceptor.secureMethod("deleteUser", "ADMIN");
        interceptor.secureMethod("viewProfile", "USER", "ADMIN");

        interceptor.setUserRoles("alice", "USER");
        interceptor.setUserRoles("bob", "ADMIN");

        String result = interceptor.invoke("alice", "viewProfile", () -> "profile data");
        System.out.println("Alice viewProfile: " + result);

        try {
            interceptor.invoke("alice", "deleteUser", () -> "deleted");
        } catch (SecurityException e) {
            System.out.println("Alice deleteUser: ACCESS DENIED");
        }

        String deleted = interceptor.invoke("bob", "deleteUser", () -> "User deleted");
        System.out.println("Bob deleteUser: " + deleted);
    }
}

import java.util.*;

public class OAuth2ScopeValidator {

    public record AccessToken(String tokenId, String clientId, Set<String> scopes, long expiresAt) {}

    private final Map<String, AccessToken> tokens = new HashMap<>();
    private final Map<String, Set<String>> resourceScopes = new HashMap<>();

    public void issueToken(String tokenId, String clientId, Set<String> scopes, long expiresAt) {
        tokens.put(tokenId, new AccessToken(tokenId, clientId, scopes, expiresAt));
    }

    public void protectResource(String resourcePath, String... requiredScopes) {
        resourceScopes.put(resourcePath, new HashSet<>(List.of(requiredScopes)));
    }

    public boolean authorize(String tokenId, String resourcePath, long currentTime) {
        // Validate token exists, is not expired, and has ALL required scopes for the resource
        return false;
    }

    public static void main(String[] args) {
        OAuth2ScopeValidator validator = new OAuth2ScopeValidator();
        validator.protectResource("/user/read", "user:read");
        validator.protectResource("/user/write", "user:read", "user:write");

        validator.issueToken("tok1", "app1", Set.of("user:read"), 9999L);
        validator.issueToken("tok2", "app2", Set.of("user:read", "user:write"), 9999L);

        System.out.println(validator.authorize("tok1", "/user/read", 1000L));  // true
        System.out.println(validator.authorize("tok1", "/user/write", 1000L)); // false
        System.out.println(validator.authorize("tok2", "/user/write", 1000L)); // true
        System.out.println(validator.authorize("tok1", "/user/read", 99999L)); // false (expired)
    }
}
